import{_ as n,H as l,o as i,c as p,S as o,J as r,C as t,a}from"./chunks/framework.f706413f.js";const b=JSON.parse('{"title":"DuckDB on Azure: direct az:// vs S3-compatible proxy","description":"","frontmatter":{"date":"2026-04-08T00:00:00.000Z","title":"DuckDB on Azure: direct az:// vs S3-compatible proxy","sidebar":false,"author":"Martin Erpicum","category":"Article","tags":["duckdb","ducklake","azure","benchmark","data"],"blog":"post","aside":"left","prev":false,"next":false},"headers":[],"relativePath":"blog/posts/2026/ducklake-azure-vs-s3proxy.md"}'),c={name:"blog/posts/2026/ducklake-azure-vs-s3proxy.md"};function d(h,e,u,y,g,f){const s=l("ImageCenter");return i(),p("div",null,[e[0]||(e[0]=o('<p><em>Summary</em>: A reproducible benchmark comparing two ways of running DuckDB against Azure Blob Storage: the native <code>azure</code> extension (<code>az://</code>) versus fronting the same storage account with a properly tuned <strong>s3proxy</strong> and using <code>httpfs</code> (<code>s3://</code>). Results across four data sizes (5k → 2M rows) show that the s3proxy path wins decisively for every operation that matters in a lakehouse workload — writes, warm reads, large cold scans, globs. The only exception is selective reads with predicate pushdown, where direct Azure wins by ~2×.</p><hr><h1 id="duckdb-on-azure-direct-az-vs-s3-compatible-proxy" tabindex="-1">DuckDB on Azure: direct <code>az://</code> vs S3-compatible proxy <a class="header-anchor" href="#duckdb-on-azure-direct-az-vs-s3-compatible-proxy" aria-label="Permalink to &quot;DuckDB on Azure: direct `az://` vs S3-compatible proxy&quot;">​</a></h1><blockquote><p><strong>TL;DR</strong> — When using DuckDB against Azure Blob Storage, fronting your Azure account with a properly tuned <strong>s3proxy</strong> (using the <code>azureblob-sdk</code> jclouds backend) is <strong>substantially faster</strong> than the native <code>az://</code> driver for almost every operation that matters in a lakehouse workload — writes (1.5–5×), warm reads (30–200×), large cold scans (5×), globs. The only exception is selective reads with predicate pushdown, where direct Azure wins by ~2×.</p></blockquote><p><strong>Table of contents</strong></p><nav class="table-of-contents"><ul><li><a href="#why-benchmark-this-at-all">Why benchmark this at all?</a></li><li><a href="#the-setup">The setup</a></li><li><a href="#the-big-picture">The big picture</a></li><li><a href="#results-operation-by-operation">Results, operation by operation</a><ul><li><a href="#single-file-parquet-writes">Single-file parquet writes</a></li><li><a href="#partitioned-writes-10-files">Partitioned writes (10 files)</a></li><li><a href="#cold-full-scan">Cold full scan</a></li><li><a href="#warm-read-log-scale">Warm read (log scale)</a></li><li><a href="#selective-read-with-predicate-pushdown">Selective read with predicate pushdown</a></li><li><a href="#glob-over-a-partitioned-dataset">Glob over a partitioned dataset</a></li></ul></li><li><a href="#full-results-table">Full results table</a></li><li><a href="#five-things-we-learned">Five things we learned</a><ul><li><a href="#_1-the-default-s3proxy-config-is-the-bottleneck-not-s3proxy-itself">1. The default s3proxy config is the bottleneck, not s3proxy itself</a></li><li><a href="#_2-the-duckdb-azure-extension-has-a-cpu-problem">2. The DuckDB azure extension has a CPU problem</a></li><li><a href="#_3-the-httpfs-metadata-cache-is-a-killer-feature-for-ducklake">3. The httpfs metadata cache is a killer feature for DuckLake</a></li><li><a href="#_4-network-matters-a-lot-for-range-request-workloads">4. Network matters a lot for range-request workloads</a></li><li><a href="#_5-direct-az-wins-at-exactly-one-thing-selective-reads-with-predicate-pushdown">5. Direct az:// wins at exactly one thing: selective reads with predicate pushdown</a></li></ul></li><li><a href="#final-verdict-for-ducklake-on-azure">Final verdict for DuckLake-on-Azure</a></li><li><a href="#reproduce-it-yourself">Reproduce it yourself</a></li><li><a href="#open-questions-next-steps">Open questions / next steps</a></li></ul></nav><hr><h2 id="why-benchmark-this-at-all" tabindex="-1">Why benchmark this at all? <a class="header-anchor" href="#why-benchmark-this-at-all" aria-label="Permalink to &quot;Why benchmark this at all?&quot;">​</a></h2><p>We run a Dagster + DuckDB/DuckLake stack at the Fédération Wallonie-Bruxelles (CFWB) and our underlying object storage is Azure Blob. DuckDB has one official way to talk to Azure — the <code>azure</code> extension, which uses <code>az://</code> URLs. But it also has a generic S3-compatible extension (<code>httpfs</code>) that can talk to any S3-compatible gateway, including <strong>s3proxy</strong>. So we have two options for how to connect DuckDB to Azure:</p><ol><li><strong>Direct</strong>, via the official <code>azure</code> extension (<code>az://container/...</code> URLs)</li><li><strong>Through an S3-compatible gateway</strong>, via the <code>httpfs</code> extension (<code>s3://bucket/...</code> URLs pointing at a local s3proxy that translates calls to Azure)</li></ol><p>The same physical storage backend, two very different code paths inside DuckDB. We had a vague feeling that performance was uneven, so we built a reproducible benchmark to find out exactly where the differences are.</p><h2 id="the-setup" tabindex="-1">The setup <a class="header-anchor" href="#the-setup" aria-label="Permalink to &quot;The setup&quot;">​</a></h2><ul><li><strong>Same Azure storage account</strong> behind both paths (so we&#39;re not measuring geography)</li><li><strong>DuckDB 1.5.1</strong> with the <code>httpfs</code> and <code>azure</code> extensions</li><li><strong>s3proxy</strong> running locally in Docker, talking to Azure</li><li>A small SQL script that: <ol><li>Generates a synthetic table in memory</li><li>Writes it as parquet (single file + partitioned) to both backends</li><li>Reads it back (cold, warm, selective filter, glob)</li><li>Times every step with <code>.timer on</code></li></ol></li></ul><p>We ran the same script across <strong>four data sizes</strong>: 5k, 50k, 500k, and 2M rows — to see how the per-request overhead amortizes as files grow.</p><p>We also tuned s3proxy in two iterations:</p><ul><li><strong>Pool tuning</strong>: bigger jclouds connection pool, OkHttp client, JVM heap.</li><li><strong>Backend swap</strong>: from the legacy <code>azureblob</code> jclouds provider to the modern <strong><code>azureblob-sdk</code></strong> (uses the official Azure Java SDK with Netty under the hood).</li></ul><hr><h2 id="the-big-picture" tabindex="-1">The big picture <a class="header-anchor" href="#the-big-picture" aria-label="Permalink to &quot;The big picture&quot;">​</a></h2><p>Before diving into individual charts, here is the whole story in a single heatmap. Each cell shows how much faster s3proxy is than direct Azure for one operation at one data size. <strong>Blue cells mean s3proxy wins, red cells mean direct Azure wins.</strong></p>',19)),r(s,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/00_summary_heatmap.png",alt:"Summary heatmap: s3proxy speedup over direct az://",width:"900"}),e[1]||(e[1]=t("p",null,`Blue dominates. The one consistently red row is "Selective read" — a genuine strength of the azure extension's range-request path. Everything else goes to s3proxy, sometimes by two orders of magnitude.`,-1)),e[2]||(e[2]=t("hr",null,null,-1)),e[3]||(e[3]=t("h2",{id:"results-operation-by-operation",tabindex:"-1"},[a("Results, operation by operation "),t("a",{class:"header-anchor",href:"#results-operation-by-operation","aria-label":'Permalink to "Results, operation by operation"'},"​")],-1)),e[4]||(e[4]=t("p",null,[a("All numbers below are from a slow "),t("strong",null,"home connection"),a(" with the tuned "),t("code",null,"azureblob-sdk"),a(" s3proxy backend.")],-1)),e[5]||(e[5]=t("h3",{id:"single-file-parquet-writes",tabindex:"-1"},[a("Single-file parquet writes "),t("a",{class:"header-anchor",href:"#single-file-parquet-writes","aria-label":'Permalink to "Single-file parquet writes"'},"​")],-1)),r(s,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/01_write_single.png",alt:"Single-file write benchmark",width:"900"}),e[6]||(e[6]=t("p",null,[a("s3proxy wins at every size by 1.5–3×. At 2M rows (80 MB parquet), direct Azure takes "),t("strong",null,"26.7 s"),a(" versus "),t("strong",null,"17.5 s"),a(" for s3proxy.")],-1)),e[7]||(e[7]=t("h3",{id:"partitioned-writes-10-files",tabindex:"-1"},[a("Partitioned writes (10 files) "),t("a",{class:"header-anchor",href:"#partitioned-writes-10-files","aria-label":'Permalink to "Partitioned writes (10 files)"'},"​")],-1)),r(s,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/02_write_partitioned.png",alt:"Partitioned write benchmark",width:"900"}),e[8]||(e[8]=t("p",null,[a("The most dramatic result. At 5k rows, s3proxy is "),t("strong",null,"5× faster"),a(". Even at 2M rows it stays "),t("strong",null,"1.6× faster"),a('. The gap on the Azure side is almost pure in-process CPU burn — see the "CPU problem" observation below.')],-1)),e[9]||(e[9]=t("h3",{id:"cold-full-scan",tabindex:"-1"},[a("Cold full scan "),t("a",{class:"header-anchor",href:"#cold-full-scan","aria-label":'Permalink to "Cold full scan"'},"​")],-1)),r(s,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/03_read_cold.png",alt:"Cold full scan benchmark",width:"900"}),e[10]||(e[10]=t("p",null,[a("Near-tie up to 500k rows. Then, at 2M rows, "),t("strong",null,"direct Azure collapses to 23.9 s"),a(" — 5× slower than s3proxy for reading the exact same parquet file. This was the most surprising finding of the whole benchmark, and it's reproducible.")],-1)),e[11]||(e[11]=t("h3",{id:"warm-read-log-scale",tabindex:"-1"},[a("Warm read (log scale) "),t("a",{class:"header-anchor",href:"#warm-read-log-scale","aria-label":'Permalink to "Warm read (log scale)"'},"​")],-1)),r(s,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/04_read_warm.png",alt:"Warm read benchmark (log scale)",width:"900"}),e[12]||(e[12]=t("p",null,[t("strong",null,"30–200× faster warm reads on s3proxy."),a(" On httpfs, DuckDB caches parquet footers and row-group metadata in memory and reuses them on subsequent queries. The azure extension does not engage that cache — every open re-fetches metadata over the wire. For DuckLake workloads, which re-open the same files constantly, this is the single most important finding.")],-1)),e[13]||(e[13]=t("h3",{id:"selective-read-with-predicate-pushdown",tabindex:"-1"},[a("Selective read with predicate pushdown "),t("a",{class:"header-anchor",href:"#selective-read-with-predicate-pushdown","aria-label":'Permalink to "Selective read with predicate pushdown"'},"​")],-1)),r(s,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/05_read_selective.png",alt:"Selective read benchmark",width:"900"}),e[14]||(e[14]=t("p",null,"The one chart where direct Azure wins consistently (by ~2× at realistic sizes). The azure extension batches range requests more aggressively than httpfs-through-s3proxy. If your workload is dominated by big parquet files with predicate pushdown — the classic OLAP fact-table pattern — this matters.",-1)),e[15]||(e[15]=t("h3",{id:"glob-over-a-partitioned-dataset",tabindex:"-1"},[a("Glob over a partitioned dataset "),t("a",{class:"header-anchor",href:"#glob-over-a-partitioned-dataset","aria-label":'Permalink to "Glob over a partitioned dataset"'},"​")],-1)),r(s,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/06_read_glob.png",alt:"Glob benchmark",width:"900"}),e[16]||(e[16]=o(`<p>Tie at small sizes; s3proxy wins by ~2× on larger data. <strong>DuckLake never globs</strong> (the catalog already has the file list), so this column is informational only, but it&#39;s worth noting that the tuned s3proxy is no longer at a disadvantage for LIST-heavy operations.</p><hr><h2 id="full-results-table" tabindex="-1">Full results table <a class="header-anchor" href="#full-results-table" aria-label="Permalink to &quot;Full results table&quot;">​</a></h2><table><thead><tr><th>Step</th><th>5k (~0.2 MB)</th><th>50k (~2 MB)</th><th>500k (~20 MB)</th><th>2M (~80 MB)</th></tr></thead><tbody><tr><td></td><td><strong>s3proxy / az://</strong></td><td><strong>s3proxy / az://</strong></td><td><strong>s3proxy / az://</strong></td><td><strong>s3proxy / az://</strong></td></tr><tr><td>WRITE single file</td><td>0.65 / 1.05</td><td>0.46 / 1.54</td><td>3.06 / 7.84</td><td>17.5 / 26.7</td></tr><tr><td>WRITE 10 partitions</td><td>1.09 / 5.71</td><td>2.21 / 11.17</td><td>6.31 / 17.3</td><td>24.4 / 38.6</td></tr><tr><td>READ cold (full scan)</td><td>0.19 / 0.23</td><td>0.40 / 0.37</td><td>1.81 / 1.45</td><td>4.40 / 23.9</td></tr><tr><td>READ warm</td><td>0.001 / 0.22</td><td>0.003 / 0.11</td><td>0.003 / 0.11</td><td>0.006 / 0.32</td></tr><tr><td>READ selective</td><td>0.06 / 0.26</td><td>1.66 / 0.72</td><td>1.43 / 0.73</td><td>2.22 / 1.36</td></tr><tr><td>READ glob (10 files)</td><td>0.42 / 0.49</td><td>0.42 / 0.41</td><td>0.34 / 0.71</td><td>0.35 / 0.62</td></tr></tbody></table><blockquote><p>Config: DuckDB 1.5.1 + s3proxy with <code>azureblob-sdk</code> backend, tuned jclouds pool (200 connections), OkHttp client, same Azure storage account behind both paths.</p></blockquote><hr><h2 id="five-things-we-learned" tabindex="-1">Five things we learned <a class="header-anchor" href="#five-things-we-learned" aria-label="Permalink to &quot;Five things we learned&quot;">​</a></h2><h3 id="_1-the-default-s3proxy-config-is-the-bottleneck-not-s3proxy-itself" tabindex="-1">1. The default s3proxy config is the bottleneck, not s3proxy itself <a class="header-anchor" href="#_1-the-default-s3proxy-config-is-the-bottleneck-not-s3proxy-itself" aria-label="Permalink to &quot;1. The default s3proxy config is the bottleneck, not s3proxy itself&quot;">​</a></h3><p>Our first run with the default <code>andrewgaul/s3proxy:latest</code> config showed s3proxy losing badly on partitioned writes and selective reads. After tuning the jclouds pool and switching to <code>azureblob-sdk</code>, write times dropped <strong>7×</strong> and read latency improved across the board.</p><p>The settings:</p><p><code>docker-compose.yml</code> snippet:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#F07178;">services</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#BABED8;">  </span><span style="color:#F07178;">s3proxy</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#BABED8;">    </span><span style="color:#F07178;">image</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">andrewgaul/s3proxy:latest</span></span>
<span class="line"><span style="color:#BABED8;">    </span><span style="color:#F07178;">container_name</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">s3proxy</span></span>
<span class="line"><span style="color:#BABED8;">    </span><span style="color:#F07178;">restart</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">unless-stopped</span></span>
<span class="line"><span style="color:#BABED8;">    </span><span style="color:#F07178;">ports</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">8080:80</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#BABED8;">    </span><span style="color:#F07178;">environment</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">S3PROXY_ENDPOINT</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">http://0.0.0.0:80</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">S3PROXY_AUTHORIZATION</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">aws-v2-or-v4</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">S3PROXY_IDENTITY</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">\${S3PROXY_IDENTITY}</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">S3PROXY_CREDENTIAL</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">\${S3PROXY_CREDENTIAL}</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">S3PROXY_VIRTUALHOST</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&quot;&quot;</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JCLOUDS_PROVIDER</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">azureblob-sdk</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JCLOUDS_IDENTITY</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">\${AZURE_STORAGE_ACCOUNT}</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JCLOUDS_CREDENTIAL</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">\${AZURE_STORAGE_KEY}</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JCLOUDS_ENDPOINT</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">https://\${AZURE_STORAGE_ACCOUNT}.blob.core.windows.net</span></span>
<span class="line"><span style="color:#89DDFF;">      </span><span style="color:#676E95;font-style:italic;"># --- HTTP / connection pooling tuning ---</span></span>
<span class="line"><span style="color:#89DDFF;">      </span><span style="color:#676E95;font-style:italic;"># Default jclouds pool is tiny (~20) and kills parallel range-GET perf.</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JCLOUDS_PROPERTY_jclouds.max-connections-per-context</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">200</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JCLOUDS_PROPERTY_jclouds.max-connections-per-host</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">100</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JCLOUDS_PROPERTY_jclouds.user-threads</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">50</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">      </span><span style="color:#676E95;font-style:italic;"># --- JVM tuning for the s3proxy process ---</span></span>
<span class="line"><span style="color:#BABED8;">      </span><span style="color:#F07178;">JAVA_TOOL_OPTIONS</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;font-style:italic;">&gt;</span><span style="color:#C792EA;">-</span></span>
<span class="line"><span style="color:#C3E88D;">        -Xmx1g</span></span>
<span class="line"><span style="color:#C3E88D;">        -XX:+UseG1GC</span></span>
<span class="line"><span style="color:#C3E88D;">        -Dhttp.maxConnections=200</span></span>
<span class="line"><span style="color:#C3E88D;">        -Dhttp.keepAlive=true</span></span></code></pre></div><p>The default <code>azureblob</code> jclouds backend is officially deprecated and uses the legacy HTTP client with a tiny ~20-connection pool. Anyone running s3proxy in front of Azure should switch immediately.</p><h3 id="_2-the-duckdb-azure-extension-has-a-cpu-problem" tabindex="-1">2. The DuckDB azure extension has a CPU problem <a class="header-anchor" href="#_2-the-duckdb-azure-extension-has-a-cpu-problem" aria-label="Permalink to &quot;2. The DuckDB azure extension has a CPU problem&quot;">​</a></h3><p>Across every run, <code>az://</code> operations burned significant CPU time inside DuckDB while s3proxy used much less. The wall-clock time was bottlenecked on in-process serialization, not network.</p><p>Compare partitioned writes at 50k rows:</p><table><thead><tr><th>Path</th><th>Real time</th><th>User CPU</th></tr></thead><tbody><tr><td>s3proxy</td><td>2.2 s</td><td>0.04 s</td></tr><tr><td>az://</td><td>11.2 s</td><td>11.2 s</td></tr></tbody></table><p>And the same pattern shows up in cold full scans at 2M rows:</p><table><thead><tr><th>Path</th><th>Real time</th><th>User CPU</th></tr></thead><tbody><tr><td>s3proxy</td><td>4.4 s</td><td>0.9 s</td></tr><tr><td>az://</td><td><strong>23.9 s</strong></td><td>20.1 s</td></tr></tbody></table><p>The azure extension isn&#39;t waiting on the network. It&#39;s spending <strong>20 seconds of single-threaded CPU time</strong> processing an 80 MB parquet file that httpfs reads in 4 seconds. Something in the azure extension&#39;s data path — block allocation, checksum, buffer copies — is dramatically more expensive than the httpfs equivalent. This is reproducible, measurable, and likely fixable upstream.</p><h3 id="_3-the-httpfs-metadata-cache-is-a-killer-feature-for-ducklake" tabindex="-1">3. The httpfs metadata cache is a killer feature for DuckLake <a class="header-anchor" href="#_3-the-httpfs-metadata-cache-is-a-killer-feature-for-ducklake" aria-label="Permalink to &quot;3. The httpfs metadata cache is a killer feature for DuckLake&quot;">​</a></h3><p>The 30–200× warm-read gap is <strong>the</strong> most important finding for lakehouse workloads. DuckLake&#39;s whole access pattern is &quot;the catalog tells me which parquet files to open, then open them&quot;. Those files get re-opened constantly as queries arrive. On httpfs (the s3proxy path), DuckDB caches the parquet footer and row-group metadata in memory. On the azure extension, that cache is not engaged — every open re-fetches metadata over the wire.</p><p>For a single query this is invisible. For a Dagster pipeline that materializes 50 assets and re-reads each one, it adds up to many seconds of pure latency per run.</p><h3 id="_4-network-matters-a-lot-for-range-request-workloads" tabindex="-1">4. Network matters a lot for range-request workloads <a class="header-anchor" href="#_4-network-matters-a-lot-for-range-request-workloads" aria-label="Permalink to &quot;4. Network matters a lot for range-request workloads&quot;">​</a></h3><p>The earlier train-network run showed s3proxy&#39;s selective-read performance collapsing to 24 s for a 2 MB file — suggesting a range-header bug. On a home fibre connection, that regression disappears entirely (1.66 s for the same query). The high-RTT mobile link was amplifying every per-request overhead, and the many parallel range fetches httpfs issues were paying the latency cost sequentially.</p><p>Takeaway: <strong>benchmark on the network you&#39;ll actually deploy on.</strong> If your Dagster workers run in the same region as your Azure storage (~1 ms RTT), the results here apply. If they run far away or over flaky links, add a larger margin on range-heavy queries.</p><h3 id="_5-direct-az-wins-at-exactly-one-thing-selective-reads-with-predicate-pushdown" tabindex="-1">5. Direct <code>az://</code> wins at exactly one thing: selective reads with predicate pushdown <a class="header-anchor" href="#_5-direct-az-wins-at-exactly-one-thing-selective-reads-with-predicate-pushdown" aria-label="Permalink to &quot;5. Direct \`az://\` wins at exactly one thing: selective reads with predicate pushdown&quot;">​</a></h3><p>In the home-network runs, direct Azure consistently beats s3proxy by ~2× on the selective-read test at 50k rows and above. This is the one workload pattern where the azure extension&#39;s internal range-request batching is genuinely better than httpfs-through-s3proxy.</p><p>This is the <strong>classic OLAP fact-table</strong> pattern: scan a few large parquet files, filter aggressively, return a tiny result. If that&#39;s your workload, direct Azure is the right choice. For everything else — and definitely for DuckLake — s3proxy wins.</p><hr><h2 id="final-verdict-for-ducklake-on-azure" tabindex="-1">Final verdict for DuckLake-on-Azure <a class="header-anchor" href="#final-verdict-for-ducklake-on-azure" aria-label="Permalink to &quot;Final verdict for DuckLake-on-Azure&quot;">​</a></h2><table><thead><tr><th>Workload pattern</th><th>Winner</th><th>Margin</th></tr></thead><tbody><tr><td>Frequent small writes (DuckLake ingestion)</td><td><strong>s3proxy</strong></td><td>1.5–3×</td></tr><tr><td>Partitioned writes</td><td><strong>s3proxy</strong></td><td>1.6–5×</td></tr><tr><td>Repeated reads of the same files (DuckLake queries)</td><td><strong>s3proxy</strong></td><td>30–200×</td></tr><tr><td>Cold full scans (small/medium)</td><td>tie</td><td>~equal</td></tr><tr><td>Cold full scans (large, 80 MB+)</td><td><strong>s3proxy</strong></td><td>5×</td></tr><tr><td>Selective scans with predicate pushdown</td><td><strong>direct azure</strong></td><td>~2×</td></tr><tr><td>Glob/LIST</td><td><strong>s3proxy</strong></td><td>~2× (irrelevant for DuckLake)</td></tr></tbody></table><p><strong>For DuckLake&#39;s actual access pattern — catalog-driven, lots of medium-sized parquet files, frequent re-opens, no globs — s3proxy + <code>azureblob-sdk</code> is the better path.</strong> The one weakness (selective range reads) only matters for a workload pattern DuckLake doesn&#39;t generate by default.</p><p>The architectural cost is one extra container in your stack. The performance win — especially on warm reads — is large enough that we&#39;re moving our CFWB DuckLake to this configuration.</p><hr><h2 id="reproduce-it-yourself" tabindex="-1">Reproduce it yourself <a class="header-anchor" href="#reproduce-it-yourself" aria-label="Permalink to &quot;Reproduce it yourself&quot;">​</a></h2><p>The full benchmark is a single SQL file you can run directly: <a href="https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/ducklake-azure-vs-s3proxy/benchmark_s3_vs_azure.sql" target="_blank" rel="noreferrer"><code>benchmark_s3_vs_azure.sql</code></a>.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># Start a tuned s3proxy in front of your Azure account (see compose snippet above)</span></span>
<span class="line"><span style="color:#FFCB6B;">docker</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">compose</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">up</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-d</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">s3proxy</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># Run the benchmark</span></span>
<span class="line"><span style="color:#FFCB6B;">duckdb</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-init</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">benchmark_s3_vs_azure.sql</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">:memory:</span></span></code></pre></div><p>Adjust the <code>range(0, N)</code> value in the script to test different data sizes.</p><hr><h2 id="open-questions-next-steps" tabindex="-1">Open questions / next steps <a class="header-anchor" href="#open-questions-next-steps" aria-label="Permalink to &quot;Open questions / next steps&quot;">​</a></h2><ul><li><strong>Re-run on DuckDB 1.6</strong> when it ships, to see if the duckdb-azure extension&#39;s CPU regression has been fixed.</li><li><strong>End-to-end Dagster pipeline benchmark</strong>: run the same materialization workload against both backends and measure total pipeline time. The synthetic gap should translate into a real-world gap of similar magnitude.</li><li><strong>Test with DuckLake-target file sizes</strong> (64–256 MB) specifically — that&#39;s the band where the architecture decision actually lands.</li><li><strong>File the azure-extension CPU overhead upstream</strong> with a minimal repro — this is the highest-leverage fix for the Azure-native path.</li></ul>`,42))])}const k=n(c,[["render",d]]);export{b as __pageData,k as default};
